using System.Collections;

class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable returns null for
        // empty env vars on Linux. Use GetEnvironmentVariables() to
        // distinguish "not set" from "explicitly empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        bool exists = Environment.GetEnvironmentVariables().Contains("MY_FLAG");
        if (!exists)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

